import {
  Box,
  Button,
  ButtonGroup,
  Flex,
  Grid,
  IconButton,
  Text,
} from "@chakra-ui/react";
import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Table, Thead, Tbody, Tr, Th, Td } from "@chakra-ui/react";
import { AddIcon } from "@chakra-ui/icons";
import { useDispatch, useSelector } from "react-redux";
import convertDateFormat, {
  deleteProduct,
  getProduct,
  getvideo,
} from "../../Redux/AdminReducer/action";
import Pagination from "./Pagination";
import AdminNavTop from "../AdminNavTop";

const GetVideos = () => {
  const store = useSelector((store) => store.AdminReducer.videos);
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [page, setPage] = useState(1);
  const limit = 4;

  const user = JSON.parse(localStorage.getItem('user'))

  useEffect(() => {
    dispatch(getvideo(page, limit, user));
  }, [page, limit]);

  const handleDelete = (id, title) => {
    // console.log(id)
    dispatch(deleteProduct(id));
    alert(`${title} is Deleted`);
  };

  const handlePageChange = (page) => {
    setPage(page);
  };

  const count = Math.ceil(store.length / limit);
  //  console.log(count)
  // console.log(count)

  const handlePageButton = (val) => {
    setPage((prev) => prev + val);
  };

  return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop />

    <Box mt="80px">
      <Flex justify="space-between" align="center" mb={6}>
        <Text fontSize="2xl" fontWeight="bold">
          Course Videos
        </Text>
      </Flex>

      <Box bg="white" p={4} borderRadius="lg" boxShadow="lg">
        <Box overflowX="auto">
          <Table variant="simple">
            <Thead bg="gray.100">
              <Tr>
                <Th>Title</Th>
                <Th>Date</Th>
                <Th>Description</Th>
                <Th>Views</Th>
                <Th>Video</Th>
                <Th>Action</Th>
              </Tr>
            </Thead>

            <Tbody>
              {store?.length > 0 ? (
                store.map((el) => (
                  <Tr key={el._id} _hover={{ bg: "gray.50" }}>
                    <Td fontWeight="medium">{el.title}</Td>

                    <Td>{convertDateFormat(el.createdAt)}</Td>

                    <Td maxW="200px" isTruncated>
                      {el.description}
                    </Td>

                    <Td>{el.views}</Td>

                    {/* LINK */}
                    <Td>
                      <a
                        href={el.link}
                        target="_blank"
                        rel="noopener noreferrer"
                        style={{ color: "#A435F0", fontWeight: "bold" }}
                      >
                        Watch
                      </a>
                    </Td>

                    {/* ACTION */}
                    <Td>
                      <Link to={`/admin/videos/add/${el.courseId}`}>
                        <Button
                          size="sm"
                          bg="#A435F0"
                          color="white"
                          _hover={{ bg: "#8710d8" }}
                        >
                          Add
                        </Button>
                      </Link>
                    </Td>
                  </Tr>
                ))
              ) : (
                <Tr>
                  <Td colSpan={6} textAlign="center" py={10}>
                    No videos found
                  </Td>
                </Tr>
              )}
            </Tbody>
          </Table>
        </Box>
      </Box>

      {/* PAGINATION */}
      <Flex justify="flex-end" mt={4} gap={2}>
        <Button
          size="sm"
          disabled={page <= 1}
          onClick={() => handlePageButton(-1)}
        >
          Prev
        </Button>

        <Pagination
          totalCount={count}
          current_page={page}
          handlePageChange={handlePageChange}
        />

        <Button
          size="sm"
          disabled={page >= count}
          onClick={() => handlePageButton(1)}
        >
          Next
        </Button>
      </Flex>
    </Box>
  </Box>
);
};

export default GetVideos;
